'use client'

import Link from 'next/link'
import { usePathname } from 'next/navigation'
import {
  LayoutDashboard, PlusCircle, History, Settings,
  Leaf, ChevronLeft, ChevronRight
} from 'lucide-react'
import { cn } from '@/lib/utils'
import { Button } from '@/components/ui/button'
import type { Profile } from '@/lib/types'
import { useState } from 'react'

const navItems = [
  { href: '/dashboard', icon: LayoutDashboard, label: '儀表板', roles: ['requester','designer','admin'] },
  { href: '/requests/new', icon: PlusCircle, label: '新增需求', roles: ['requester','admin'] },
  { href: '/history', icon: History, label: '歷史資料', roles: ['requester','designer','admin'] },
  { href: '/admin', icon: Settings, label: '系統管理', roles: ['admin'] },
]

interface SidebarProps {
  profile: Profile
}

export function Sidebar({ profile }: SidebarProps) {
  const pathname = usePathname()
  const [collapsed, setCollapsed] = useState(false)

  const visibleItems = navItems.filter(item => item.roles.includes(profile.role))

  return (
    <aside className={cn(
      'relative flex flex-col bg-brand-800 text-white transition-all duration-300 shrink-0',
      collapsed ? 'w-16' : 'w-56'
    )}>
      {/* Logo */}
      <div className={cn(
        'flex items-center gap-3 px-4 py-5 border-b border-brand-700',
        collapsed && 'justify-center px-0'
      )}>
        <div className="flex items-center justify-center w-8 h-8 rounded-lg bg-white/20 shrink-0">
          <Leaf className="h-5 w-5 text-white" />
        </div>
        {!collapsed && (
          <div className="overflow-hidden">
            <p className="font-bold text-sm leading-tight truncate">淨淨 Clean Clean</p>
            <p className="text-xs text-brand-300 truncate">設計需求管理</p>
          </div>
        )}
      </div>

      {/* Nav */}
      <nav className="flex-1 py-4 px-2 space-y-1">
        {visibleItems.map(({ href, icon: Icon, label }) => {
          const active = pathname === href || pathname.startsWith(href + '/')
          return (
            <Link
              key={href}
              href={href}
              className={cn(
                'flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors',
                active
                  ? 'bg-white/20 text-white'
                  : 'text-brand-200 hover:bg-white/10 hover:text-white',
                collapsed && 'justify-center px-2'
              )}
              title={collapsed ? label : undefined}
            >
              <Icon className="h-5 w-5 shrink-0" />
              {!collapsed && <span>{label}</span>}
            </Link>
          )
        })}
      </nav>

      {/* Collapse toggle */}
      <button
        onClick={() => setCollapsed(v => !v)}
        className="absolute -right-3 top-20 flex items-center justify-center w-6 h-6 rounded-full bg-brand-700 border border-brand-600 text-white hover:bg-brand-600 transition-colors z-10"
      >
        {collapsed
          ? <ChevronRight className="h-3 w-3" />
          : <ChevronLeft className="h-3 w-3" />
        }
      </button>

      {/* Role badge at bottom */}
      {!collapsed && (
        <div className="px-4 py-3 border-t border-brand-700">
          <div className="text-xs text-brand-300">
            {{requester:'需求方', designer:'設計師', admin:'管理員'}[profile.role]}
          </div>
        </div>
      )}
    </aside>
  )
}
